<script setup lang="ts">
import { recipes } from "~/data/recipes";

const route = useRoute();
const recipe = computed(() => recipes.find((r) => r.slug === route.params.slug));

if (!recipe.value) {
  throw createError({ statusCode: 404, statusMessage: "Recipe not found" });
}

useHead({
  title: `${recipe.value.title} — Verdant Kitchen`,
  meta: [{ name: "description", content: recipe.value.tagline }],
});

const difficultyColor = computed(() => {
  switch (recipe.value?.difficulty) {
    case "Easy":
      return "text-mint bg-mint/15";
    case "Medium":
      return "text-gold bg-gold/15";
    case "Hard":
      return "text-red-400 bg-red-400/15";
    default:
      return "";
  }
});
</script>

<template>
  <div v-if="recipe" class="min-h-screen bg-[#0e0e0e]">
    <!-- Hero -->
    <div class="relative h-[60vh] min-h-[420px] w-full overflow-hidden">
      <img
        :src="recipe.image"
        :alt="recipe.title"
        class="h-full w-full object-cover"
      />
      <div class="absolute inset-0 bg-gradient-to-t from-[#0e0e0e] via-[#0e0e0e]/60 to-transparent" />
      <div class="absolute inset-0 shadow-[inset_0_-120px_100px_-40px_rgba(0,0,0,0.9)]" />

      <div class="absolute bottom-0 left-0 right-0 p-8 sm:p-12">
        <div class="mx-auto max-w-4xl">
          <NuxtLink
            to="/"
            class="mb-6 inline-flex items-center gap-2 text-sm font-medium text-cream/50 transition-colors hover:text-mint"
          >
            <IconArrowLeft class="h-4 w-4" />
            Back to recipes
          </NuxtLink>
          <h1 class="text-4xl font-extrabold leading-tight text-cream sm:text-6xl">
            {{ recipe.title }}
          </h1>
          <p class="mt-3 text-lg font-light text-cream/60">
            {{ recipe.tagline }}
          </p>
        </div>
      </div>
    </div>

    <!-- Meta bar -->
    <div class="border-b border-white/5">
      <div class="mx-auto flex max-w-4xl flex-wrap items-center gap-6 px-8 py-6 sm:px-12">
        <MetaPill label="Prep" :value="recipe.prepTime">
          <IconClock class="h-4 w-4" />
        </MetaPill>
        <MetaPill label="Cook" :value="recipe.cookTime">
          <IconFlame class="h-4 w-4" />
        </MetaPill>
        <span
          :class="difficultyColor"
          class="rounded-full px-3 py-1 text-xs font-bold tracking-wider uppercase"
        >
          {{ recipe.difficulty }}
        </span>
      </div>
    </div>

    <!-- Content -->
    <div class="mx-auto max-w-4xl px-8 py-16 sm:px-12">
      <div class="grid gap-16 lg:grid-cols-[1fr_1.8fr]">
        <!-- Ingredients -->
        <div>
          <h2 class="mb-6 text-2xl font-bold text-gold">Ingredients</h2>
          <ul class="space-y-3">
            <li
              v-for="(item, i) in recipe.ingredients"
              :key="i"
              class="flex items-start gap-3 text-[15px] leading-relaxed text-cream/80"
            >
              <span class="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-mint/60" />
              {{ item }}
            </li>
          </ul>
        </div>

        <!-- Steps -->
        <div>
          <h2 class="mb-6 text-2xl font-bold text-gold">Preparation</h2>
          <ol class="space-y-8">
            <li
              v-for="(step, i) in recipe.steps"
              :key="i"
              class="flex gap-5"
            >
              <span class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-teal/20 text-sm font-bold text-teal">
                {{ i + 1 }}
              </span>
              <p class="pt-1 text-[15px] leading-relaxed text-cream/80">
                {{ step }}
              </p>
            </li>
          </ol>
        </div>
      </div>
    </div>

    <!-- Footer -->
    <footer class="border-t border-white/5 py-12 text-center text-xs text-cream/30">
      Verdant Kitchen &mdash; Plant-Powered Cooking
    </footer>
  </div>
</template>
